<content>"""
WebSocket Client for IRS Routing System
Example client for connecting to the WebSocket server
"""

import asyncio
import json
import logging
from datetime import datetime
import websockets

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class WebSocketClient:
    """Client for connecting to IRS WebSocket server"""

    def __init__(self, uri: str = "ws://localhost:8765"):
        self.uri = uri
        self.websocket = None

    async def connect(self):
        """Connect to the WebSocket server"""
        try:
            self.websocket = await websockets.connect(self.uri)
            logger.info(f"Connected to {self.uri}")
            return True
        except Exception as e:
            logger.error(f"Connection failed: {e}")
            return False

    async def send_route_request(self, query: str):
        """Send a routing request to the server"""
        if not self.websocket:
            logger.error("Not connected to server")
            return None

        try:
            message = {
                "type": "route",
                "query": query,
                "timestamp": datetime.now().isoformat()
            }
            await self.websocket.send(json.dumps(message))
            logger.info(f"Sent routing request: {query[:50]}...")

            # Wait for response
            response = await self.websocket.recv()
            return json.loads(response)

        except Exception as e:
            logger.error(f"Error sending request: {e}")
            return None

    async def request_stats(self):
        """Request server statistics"""
        if not self.websocket:
            logger.error("Not connected to server")
            return None

        try:
            message = {"type": "stats"}
            await self.websocket.send(json.dumps(message))

            response = await self.websocket.recv()
            return json.loads(response)

        except Exception as e:
            logger.error(f"Error requesting stats: {e}")
            return None

    async def send_ping(self):
        """Send a ping to test connection"""
        if not self.websocket:
            logger.error("Not connected to server")
            return None

        try:
            message = {"type": "ping"}
            await self.websocket.send(json.dumps(message))

            response = await self.websocket.recv()
            return json.loads(response)

        except Exception as e:
            logger.error(f"Error sending ping: {e}")
            return None

    async def listen_for_broadcasts(self):
        """Listen for broadcast messages from the server"""
        if not self.websocket:
            logger.error("Not connected to server")
            return

        try:
            async for message in self.websocket:
                data = json.loads(message)
                logger.info(f"Received broadcast: {data.get('type')}")
                print(json.dumps(data, indent=2))

        except websockets.exceptions.ConnectionClosed:
            logger.info("Connection closed by server")
        except Exception as e:
            logger.error(f"Error listening for broadcasts: {e}")

    async def close(self):
        """Close the WebSocket connection"""
        if self.websocket:
            await self.websocket.close()
            logger.info("Connection closed")


async def interactive_demo():
    """Interactive demonstration of the WebSocket client"""
    client = WebSocketClient()

    if not await client.connect():
        return

    try:
        while True:
            print("\n=== WebSocket Client Menu ===")
            print("1. Send routing request")
            print("2. Request statistics")
            print("3. Send ping")
            print("4. Listen for broadcasts (Ctrl+C to stop)")
            print("5. Exit")

            choice = input("\nEnter choice (1-5): ").strip()

            if choice == "1":
                query = input("Enter query: ").strip()
                if query:
                    result = await client.send_route_request(query)
                    if result:
                        print("\nResponse:")
                        print(json.dumps(result, indent=2))

            elif choice == "2":
                stats = await client.request_stats()
                if stats:
                    print("\nServer Statistics:")
                    print(json.dumps(stats, indent=2))

            elif choice == "3":
                pong = await client.send_ping()
                if pong:
                    print("\nPong received:")
                    print(json.dumps(pong, indent=2))

            elif choice == "4":
                print("\nListening for broadcasts (press Ctrl+C to stop)...")
                try:
                    await client.listen_for_broadcasts()
                except KeyboardInterrupt:
                    print("\nStopped listening")

            elif choice == "5":
                break

            else:
                print("Invalid choice")

    finally:
        await client.close()


async def automated_test():
    """Automated test of the WebSocket client"""
    client = WebSocketClient()

    if not await client.connect():
        return

    try:
        # Test ping
        print("\n=== Testing Ping ===")
        pong = await client.send_ping()
        print(json.dumps(pong, indent=2))

        # Test routing requests
        print("\n=== Testing Routing Requests ===")
        test_queries = [
            "What is the capital of France?",
            "Explain quantum computing in simple terms",
            "Write a Python function to calculate fibonacci numbers"
        ]

        for query in test_queries:
            print(f"\nQuery: {query}")
            result = await client.send_route_request(query)
            print(json.dumps(result, indent=2))
            await asyncio.sleep(1)

        # Test stats request
        print("\n=== Testing Stats Request ===")
        stats = await client.request_stats()
        print(json.dumps(stats, indent=2))

    finally:
        await client.close()


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "--test":
        asyncio.run(automated_test())
    else:
        asyncio.run(interactive_demo())
