        <div class="card">
            <h2>Output Log</h2>
            <div class="output" id="output"></div>
        </div>
    </div>

    <script>
        let ws = null;

        function log(message, type = 'info') {
            const output = document.getElementById('output');
            const timestamp = new Date().toLocaleTimeString();
            const messageDiv = document.createElement('div');
            messageDiv.className = `message ${type}`;
            messageDiv.textContent = `[${timestamp}] ${message}`;
            output.appendChild(messageDiv);
            output.scrollTop = output.scrollHeight;
        }

        function updateStatus(connected) {
            const indicator = document.getElementById('statusIndicator');
            const statusText = document.getElementById('statusText');
            const connectBtn = document.getElementById('connectBtn');
            const disconnectBtn = document.getElementById('disconnectBtn');
            const pingBtn = document.getElementById('pingBtn');
            const statsBtn = document.getElementById('statsBtn');
            const routeBtn = document.getElementById('routeBtn');

            if (connected) {
                indicator.classList.add('connected');
                statusText.textContent = 'Connected';
                connectBtn.disabled = true;
                disconnectBtn.disabled = false;
                pingBtn.disabled = false;
                statsBtn.disabled = false;
                routeBtn.disabled = false;
            } else {
                indicator.classList.remove('connected');
                statusText.textContent = 'Disconnected';
                connectBtn.disabled = false;
                disconnectBtn.disabled = true;
                pingBtn.disabled = true;
                statsBtn.disabled = true;
                routeBtn.disabled = true;
            }
        }

        function updateStats(stats) {
            if (stats.data) {
                document.getElementById('totalRequests').textContent = stats.data.total_requests || 0;
                document.getElementById('successfulRoutes').textContent = stats.data.successful_routes || 0;
                document.getElementById('failedRoutes').textContent = stats.data.failed_routes || 0;
            }
            if (stats.connected_clients !== undefined) {
                document.getElementById('connectedClients').textContent = stats.connected_clients;
            }
        }

        function connect() {
            const url = document.getElementById('wsUrl').value;

            try {
                ws = new WebSocket(url);

                ws.onopen = () => {
                    log('Connected to WebSocket server', 'success');
                    updateStatus(true);
                };

                ws.onmessage = (event) => {
                    try {
                        const data = JSON.parse(event.data);
                        log(`Received: ${data.type}`, 'info');
                        console.log('Message:', data);

                        if (data.type === 'stats' || data.type === 'system_status') {
                            updateStats(data);
                        } else if (data.type === 'connection') {
                            updateStats(data.stats);
                        } else if (data.type === 'routing_result') {
                            log(`Routing result: ${data.result}`, 'success');
                        } else if (data.type === 'error') {
                            log(`Error: ${data.message}`, 'error');
                        }
                    } catch (e) {
                        log(`Error parsing message: ${e.message}`, 'error');
                    }
                };

                ws.onerror = (error) => {
                    log('WebSocket error occurred', 'error');
                    console.error('WebSocket error:', error);
                };

                ws.onclose = () => {
                    log('Disconnected from WebSocket server', 'info');
                    updateStatus(false);
                    ws = null;
                };

            } catch (e) {
                log(`Connection error: ${e.message}`, 'error');
            }
        }

        function disconnect() {
            if (ws) {
                ws.close();
            }
        }

        function sendPing() {
            if (ws && ws.readyState === WebSocket.OPEN) {
                const message = { type: 'ping' };
                ws.send(JSON.stringify(message));
                log('Sent ping', 'info');
            }
        }

        function requestStats() {
            if (ws && ws.readyState === WebSocket.OPEN) {
                const message = { type: 'stats' };
                ws.send(JSON.stringify(message));
                log('Requested statistics', 'info');
            }
        }

        function sendRouteRequest() {
            if (ws && ws.readyState === WebSocket.OPEN) {
                const query = document.getElementById('queryInput').value;
                if (!query.trim()) {
                    log('Please enter a query', 'error');
                    return;
                }

                const message = {
                    type: 'route',
                    query: query,
                    timestamp: new Date().toISOString()
                };
                ws.send(JSON.stringify(message));
                log(`Sent routing request: ${query.substring(0, 50)}...`, 'info');
            }
        }

        function clearOutput() {
            document.getElementById('output').innerHTML = '';
        }
    </script>
</body>
