<content>"""
Example: Integrating WebSocket Server with IRS Router
Shows how to use the WebSocket server in real applications
"""

import asyncio
import sys
import os

# Add parent directory to path
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

from src.websocket_client import WebSocketClient


async def batch_routing_example():
    """Example: Batch process multiple queries via WebSocket"""
    print("=== Batch Routing Example ===\n")

    queries = [
        "What is machine learning?",
        "How do I implement a binary search tree?",
        "Explain quantum computing",
        "What's the weather like?",
        "Write a function to reverse a string"
    ]

    client = WebSocketClient()

    if not await client.connect():
        print("Failed to connect to server")
        return

    print(f"Processing {len(queries)} queries...\n")

    results = []
    for i, query in enumerate(queries, 1):
        print(f"{i}. Query: {query}")
        result = await client.send_route_request(query)

        if result and result.get("type") == "routing_result":
            model = result.get("result")
            print(f"   → Routed to: {model}\n")
            results.append((query, model))
        else:
            print(f"   → Failed\n")

        await asyncio.sleep(0.5)

    # Get final statistics
    stats = await client.request_stats()
    if stats:
        print("\n=== Statistics ===")
        data = stats.get("data", {})
        print(f"Total Requests: {data.get('total_requests', 0)}")
        print(f"Successful Routes: {data.get('successful_routes', 0)}")
        print(f"Success Rate: {data.get('successful_routes', 0) / data.get('total_requests', 1) * 100:.1f}%")

    await client.close()
    return results


async def real_time_monitoring_example():
    """Example: Monitor routing decisions in real-time"""
    print("=== Real-time Monitoring Example ===\n")
    print("Monitoring for 30 seconds. Send queries from another client...\n")

    client = WebSocketClient()

    if not await client.connect():
        print("Failed to connect to server")
        return

    # Listen for broadcasts with timeout
    try:
        await asyncio.wait_for(
            client.listen_for_broadcasts(),
            timeout=30.0
        )
    except asyncio.TimeoutError:
        print("\nMonitoring period ended")

    await client.close()


async def performance_test_example():
    """Example: Test routing performance with multiple queries"""
    print("=== Performance Test Example ===\n")

    client = WebSocketClient()

    if not await client.connect():
        print("Failed to connect to server")
        return

    import time

    num_queries = 50
    print(f"Sending {num_queries} queries to measure performance...\n")

    start_time = time.time()

    for i in range(num_queries):
        query = f"Test query number {i+1}"
        await client.send_route_request(query)

        if (i + 1) % 10 == 0:
            print(f"Processed {i+1}/{num_queries} queries...")

    elapsed = time.time() - start_time

    print(f"\n=== Performance Results ===")
    print(f"Total Queries: {num_queries}")
    print(f"Time Elapsed: {elapsed:.2f} seconds")
    print(f"Queries/Second: {num_queries/elapsed:.2f}")
    print(f"Average Latency: {elapsed/num_queries*1000:.2f} ms")

    await client.close()


async def error_handling_example():
    """Example: Demonstrate error handling"""
    print("=== Error Handling Example ===\n")

    client = WebSocketClient()

    if not await client.connect():
        print("Failed to connect to server")
        return

    # Test 1: Empty query
    print("1. Testing empty query...")
    result = await client.send_route_request("")
    if result and result.get("type") == "error":
        print(f"   ✓ Error handled: {result.get('message')}\n")

    # Test 2: Valid query
    print("2. Testing valid query...")
    result = await client.send_route_request("What is Python?")
    if result and result.get("type") == "routing_result":
        print(f"   ✓ Success: Routed to {result.get('result')}\n")

    # Test 3: Invalid message type
    print("3. Testing invalid message type...")
    try:
        await client.websocket.send('{"type": "invalid"}')
        response = await client.websocket.recv()
        response_data = eval(response)  # For demo only
        if response_data.get("type") == "error":
            print(f"   ✓ Error handled: {response_data.get('message')}\n")
    except Exception as e:
        print(f"   Exception: {e}\n")

    await client.close()


async def main():
    """Main entry point for examples"""
    examples = {
        "1": ("Batch Routing", batch_routing_example),
        "2": ("Real-time Monitoring", real_time_monitoring_example),
        "3": ("Performance Test", performance_test_example),
        "4": ("Error Handling", error_handling_example),
    }

    print("\n" + "="*60)
    print("WebSocket Integration Examples")
    print("="*60)
    print("\nAvailable examples:")
    for key, (name, _) in examples.items():
        print(f"  {key}. {name}")
    print("  q. Quit")

    while True:
        print("\n" + "="*60)
        choice = input("Select an example (1-4, q to quit): ").strip()

        if choice.lower() == 'q':
            break

        if choice in examples:
            name, example_func = examples[choice]
            print(f"\nRunning: {name}\n")
            try:
                await example_func()
            except KeyboardInterrupt:
                print("\n\nExample interrupted")
            except Exception as e:
                print(f"\nError running example: {e}")

            input("\nPress Enter to continue...")
        else:
            print("Invalid choice")

    print("\nGoodbye!")


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("\n\nExiting...")
